      *n = *y.n;
    }

    x(x&& y) {
      int* tmp = n; n = y.n; y.n = tmp;
    }


    ~x() {
      delete n;
    }

    x& operator=(const x& y) {
      if (this!= y) {
	*n = *y.n;
      }
      return *this;
    }

    x& operator=(x y) {
      *this = x();
      return *this;
    }
    int* n;
